#include <cuda.h>
#include <cuda_runtime.h>
#include <stdlib.h>
#include <stdio.h>
#include <math.h>

#include "./../main.h"
#include "./../util/timer/timer.h"

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

typedef struct {
    fp alpha;
    fp a2;
} par_gpu;

typedef struct {
    int number_boxes;
    int number_par_per_box;
} dim_gpu;

__device__ FOUR_VECTOR d_rv[100000]; // Placeholder, actual size handled via pointer
__device__ fp d_qv[100000];
__device__ FOUR_VECTOR d_fv[100000];
__device__ box_str d_box[1000];

__global__ void kernel_gpu(
    par_gpu par,
    dim_gpu dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int l = blockIdx.x;
    if (l >= dim.number_boxes) return;

    int first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    fp alpha = par.alpha;
    fp a2 = par.a2;

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        int first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            FOUR_VECTOR rA_i = rA[i];
            FOUR_VECTOR fA_i = fA[i];

            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                FOUR_VECTOR rB_j = rB[j];
                fp qB_j = qB[j];

                fp r2 = rA_i.v + rB_j.v - DOT(rA_i, rB_j);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0 * vij;

                THREE_VECTOR d;
                d.x = rA_i.x - rB_j.x;
                d.y = rA_i.y - rB_j.y;
                d.z = rA_i.z - rB_j.z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA_i.v += qB_j * vij;
                fA_i.x += qB_j * fxij;
                fA_i.y += qB_j * fyij;
                fA_i.z += qB_j * fzij;
            }
            fA[i] = fA_i;
        }
    }
}

void kernel_cpu(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    long long time0 = get_time();
    long long time1, time2, time3, time4;

    time1 = get_time();

    setdevice();
    time2 = get_time();

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;
    time3 = get_time();

    // Allocate GPU memory
    box_str* d_box;
    FOUR_VECTOR* d_rv;
    fp* d_qv;
    FOUR_VECTOR* d_fv;

    size_t box_size = dim.number_boxes * sizeof(box_str);
    size_t vec_size = dim.space_elem * sizeof(FOUR_VECTOR);
    size_t fp_size = dim.space_elem * sizeof(fp);

    cudaMalloc(&d_box, box_size);
    cudaMalloc(&d_rv, vec_size);
    cudaMalloc(&d_qv, fp_size);
    cudaMalloc(&d_fv, vec_size);

    // Copy data to GPU
    cudaMemcpy(d_box, box, box_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_rv, rv, vec_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_qv, qv, fp_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_fv, fv, vec_size, cudaMemcpyHostToDevice);

    // Setup parameters
    par_gpu par_gpu;
    par_gpu.alpha = alpha;
    par_gpu.a2 = a2;

    dim_gpu dim_gpu;
    dim_gpu.number_boxes = dim.number_boxes;
    dim_gpu.number_par_per_box = NUMBER_PAR_PER_BOX;

    // Launch kernel
    kernel_gpu<<<dim.number_boxes, 1>>>(par_gpu, dim_gpu, d_box, d_rv, d_qv, d_fv);
    cudaDeviceSynchronize();

    // Copy result back
    cudaMemcpy(fv, d_fv, vec_size, cudaMemcpyDeviceToHost);

    // Free GPU memory
    cudaFree(d_box);
    cudaFree(d_rv);
    cudaFree(d_qv);
    cudaFree(d_fv);

    time4 = get_time();

    printf("Time spent in different stages of GPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: VARIABLES\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: INPUTS\n", (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time4-time0)*100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4-time0)/1000000);
}

#ifdef __cplusplus
}
#endif

